),
kpi_main AS (
    SELECT
        COUNT(DISTINCT nct_id)                                                         AS total_trials,
        COUNT(DISTINCT CASE WHEN overall_status IN
            ('RECRUITING', 'ACTIVE_NOT_RECRUITING') THEN nct_id END)                   AS active_trials,
        COUNT(DISTINCT CASE WHEN overall_status = 'COMPLETED' THEN nct_id END)         AS completed_trials,
        COUNT(DISTINCT CASE WHEN results_first_submitted_date IS NOT NULL
            THEN nct_id END)                                                           AS trials_with_results,
        PERCENTILE_CONT(0.5) WITHIN GROUP (ORDER BY enrollment)                        AS median_enrollment
    FROM scoped
),
kpi_sponsors AS (
    SELECT COUNT(DISTINCT sp.name) AS unique_sponsors
    FROM ctgov.sponsors sp
    WHERE sp.nct_id IN (SELECT nct_id FROM scoped)
      AND sp.lead_or_collaborator = 'lead'
),
kpi_drugs AS (
    SELECT COUNT(DISTINCT dt.brand_name) AS unique_drugs
    FROM public.drug_trials dt
    WHERE dt.nct_id IN (SELECT nct_id FROM scoped)
),
kpi_conditions AS (
    SELECT COUNT(DISTINCT bc.downcase_mesh_term) AS unique_conditions
    FROM ctgov.browse_conditions bc
    WHERE bc.nct_id IN (SELECT nct_id FROM scoped)
      AND bc.mesh_type = 'mesh-list'
),
kpi_pros AS (
    SELECT COUNT(DISTINCT p.nct_id) AS trials_with_pros
    FROM public.drug_trial_design_outcomes_pro p
    WHERE p.nct_id IN (SELECT nct_id FROM scoped)
)
SELECT
    'ind:Acute Lymphoblastic Leukemia|Acute Myeloid Leukemia|Adrenal Cancer|Advanced / Metastatic Solid Tumor|Anal Cancer|Anaplastic Large Cell Lymphoma|Appendiceal Cancer|Asthma|Atopic Dermatitis / Eczema|Basal Cell Carcinoma|Biliary Tract Cancer / Cholangiocarcinoma|Bone Metastases|Brain / Central Nervous System Tumor|Breast Cancer|Burkitt Lymphoma|Cancer / Neoplasm|Cancer Treatment / Therapy Concept|Cancer of Unknown Primary|Cervical Cancer|Chronic Lymphocytic Leukemia / Small Lymphocytic Lymphoma|Chronic Myeloid Leukemia|Chronic Myelomonocytic Leukemia|Chronic Obstructive Pulmonary Disease|Colorectal Cancer|Cutaneous Squamous Cell Carcinoma|Diffuse Large B-Cell Lymphoma|Endometrial / Uterine Cancer|Esophageal Cancer|Familial Adenomatous Polyposis|Follicular Lymphoma|Gastric Cancer|Gastroesophageal Junction Cancer|Gastrointestinal Stromal Tumor|Head and Neck Cancer|Hematologic Malignancy|Hodgkin Lymphoma|Kaposi Sarcoma|Kidney Cancer / Renal Cell Carcinoma|Leukemia|Liver Cancer / Hepatocellular Carcinoma|Lung Cancer|Lymphoma|Mantle Cell Lymphoma|Marginal Zone Lymphoma|Melanoma|Merkel Cell Carcinoma|Mesothelioma|Multiple Myeloma / Plasma Cell Neoplasm|Myelodysplastic Syndrome|Myeloproliferative Neoplasm|Neuroendocrine Tumor / Carcinoid Tumor|Non-Small Cell Lung Cancer|Ovarian / Fallopian Tube / Primary Peritoneal Cancer|Pancreatic Cancer|Prostate Cancer|Sarcoma / Soft Tissue or Bone Tumor|Small Cell Lung Cancer|Systemic Mastocytosis|T-Cell / NK-Cell Lymphoma|Thymic Cancer|Thyroid Cancer|Urothelial / Bladder Cancer|Vaginal / Vulvar Cancer',
    kpi_main.total_trials,
    kpi_main.active_trials,
    kpi_main.completed_trials,
    kpi_main.trials_with_results,
    kpi_main.median_enrollment,
    kpi_sponsors.unique_sponsors,
    kpi_drugs.unique_drugs,
    kpi_conditions.unique_conditions,
    kpi_pros.trials_with_pros,
    '2026-07-11 17:15:40+00'::timestamptz
FROM kpi_main, kpi_sponsors, kpi_drugs, kpi_conditions, kpi_pros
ON CONFLICT (scope_key) DO UPDATE SET
    total_trials        = EXCLUDED.total_trials,
    active_trials       = EXCLUDED.active_trials,
    completed_trials    = EXCLUDED.completed_trials,
    trials_with_results = EXCLUDED.trials_with_results,
    median_enrollment   = EXCLUDED.median_enrollment,
    unique_sponsors     = EXCLUDED.unique_sponsors,
    unique_drugs        = EXCLUDED.unique_drugs,
    unique_conditions   = EXCLUDED.unique_conditions,
    trials_with_pros    = EXCLUDED.trials_with_pros,
    refreshed_at        = EXCLUDED.refreshed_at;

